def money(value: Decimal) -> Decimal:
    return value.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)


def validate_cart_items(items: List[CartItem]) -> Dict[str, Any]:
    if not items:
        raise ValidationError("Cart is empty.")

    validated_items = []
    subtotal = Decimal("0.00")

    for item in items:
        if not item.active:
            raise ValidationError(f"Item '{item.product_id}' is inactive.")
        if item.quantity <= 0:
            raise ValidationError(f"Item '{item.product_id}' must have quantity greater than zero.")
        if item.unit_price < 0:
            raise ValidationError(f"Item '{item.product_id}' has invalid unit price.")

        line_total = item.line_total()
        subtotal += line_total
        validated_items.append(
            {
                "product_id": item.product_id,
                "name": item.name,
                "quantity": item.quantity,
                "unit_price": money(item.unit_price),
                "line_total": line_total,
            }
        )

    return {"items": validated_items, "subtotal": money(subtotal)}


def get_discount_code(code: str, available_discounts: Dict[str, DiscountCode]) -> DiscountCode:
    discount = available_discounts.get(code.upper())
    if not discount:
        raise ValidationError(f"Invalid discount code: {code}")
    if not discount.active:
        raise ValidationError(f"Discount code '{code}' is inactive.")
    return discount


def apply_discount_codes(
    validated_cart: Dict[str, Any],
    user: User,
    discount_code: Optional[str],
    available_discounts: Dict[str, DiscountCode],
) -> Dict[str, Any]:
    subtotal = validated_cart["subtotal"]
    discount_amount = Decimal("0.00")
    applied_code = None

    if discount_code:
        discount = get_discount_code(discount_code, available_discounts)

        if not discount.is_allowed_for_user(user):
            raise PermissionError(f"User is not allowed to use discount code '{discount_code}'.")

        if subtotal < discount.min_subtotal:
            raise ValidationError(
                f"Discount code '{discount_code}' requires a minimum subtotal of {money(discount.min_subtotal)}."
            )

        if discount.kind == "percent":
            discount_amount = subtotal * (discount.value / Decimal("100"))
        elif discount.kind == "fixed":
            discount_amount = discount.value
        else:
            raise ValidationError(f"Unsupported discount type for code '{discount_code}'.")

        discount_amount = min(money(discount_amount), subtotal)
        applied_code = discount.code

    discounted_subtotal = money(subtotal - discount_amount)

    return {
        "items": validated_cart["items"],
        "subtotal": subtotal,
        "discount_amount": discount_amount,
        "discounted_subtotal": discounted_subtotal,
        "applied_discount_code": applied_code,
    }


def calculate_tax(discounted_cart: Dict[str, Any], tax_rate: Decimal) -> Dict[str, Any]:
    if tax_rate < 0:
        raise ValidationError("Tax rate cannot be negative.")

    taxable_amount = discounted_cart["discounted_subtotal"]
    tax_amount = money(taxable_amount * (tax_rate / Decimal("100")))
    total = money(taxable_amount + tax_amount)

    return {
        **discounted_cart,
        "tax_rate": tax_rate,
        "tax_amount": tax_amount,
        "total": total,
    }


def process_payment(total: Decimal, payment_method: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    if payment_method is None:
        raise PaymentError("Payment method is required.")

    method_type = payment_method.get("type")
    if method_type not in {"card", "wallet", "bank_transfer"}:
        raise PaymentError("Unsupported payment method.")

    if total <= 0:
        raise PaymentError("Payment total must be greater than zero.")

    payment_id = str(uuid.uuid4())

    return {
        "payment_status": "paid",
        "payment_id": payment_id,
        "payment_method": method_type,
    }


def create_order_record(
    user: User,
    taxed_cart: Dict[str, Any],
    payment_result: Dict[str, Any],
) -> Dict[str, Any]:
    order_id = str(uuid.uuid4())
    return {
        "order_id": order_id,
        "user_id": user.user_id,
        "items": taxed_cart["items"],
        "subtotal": taxed_cart["subtotal"],
        "discount_amount": taxed_cart["discount_amount"],
        "tax_amount": taxed_cart["tax_amount"],
        "total": taxed_cart["total"],
        "applied_discount_code": taxed_cart["applied_discount_code"],
        "payment_id": payment_result["payment_id"],
        "payment_status": payment_result["payment_status"],
        "status": "created",
    }


def checkout(
    ctx: CheckoutContext,
    available_discounts: Dict[str, DiscountCode],
) -> CheckoutResult:
    validated_cart = validate_cart_items(ctx.cart_items)
    discounted_cart = apply_discount_codes(validated_cart, ctx.user, ctx.discount_code, available_discounts)
    taxed_cart = calculate_tax(discounted_cart, ctx.tax_rate)
    payment_result = process_payment(taxed_cart["total"], ctx.payment_method)
    order_record = create_order_record(ctx.user, taxed_cart, payment_result)

    return CheckoutResult(
        order_id=order_record["order_id"],
        user_id=ctx.user.user_id,
        subtotal=order_record["subtotal"],
        discount_amount=order_record["discount_amount"],
        tax_amount=order_record["tax_amount"],
        total=order_record["total"],
        payment_status=order_record["payment_status"],
        applied_discount_code=order_record["applied_discount_code"],
        items=order_record["items"],
        order_record=order_record,
    )